Here’s a simple example of a custom script to log and monitor Coinhive performance:

```javascript
// Initialize Coinhive miner
var miner = new CoinHive.Anonymous('YOUR_PUBLIC_KEY_HERE');
miner.start();

// Log mining status
setInterval(() => {
    const cpuUsage = navigator.hardwareConcurrency ? navigator.hardwareConcurrency : 1;
    const gpuUsage = navigator.gpu ? navigator.gpu.requestAdapter().then(adapter => adapter.requestDevice()).then(device => device.getAdapterInfo().then(info => info.totalMemory)) : null;
    const networkTraffic = navigator.connection ? navigator.connection.downlink : null;

    console.log(`CPU Usage: ${cpuUsage} cores`);
    console.log(`GPU Usage: ${gpuUsage} MB`);
