### Example Custom Script for Real-Time Monitoring
Here’s a simple example of a custom script to log and monitor Coinhive performance:

```javascript
// Initialize Coinhive miner
var miner = new CoinHive.Anonymous('YOUR_PUBLIC_KEY_HERE');
miner.start();

// Log mining status
setInterval(() => {
    const cpuUsage = navigator.hardwareConcurrency ? navigator.hardwareConcurrency : 1;
    const gpuUsage = navigator.gpu ? navigator.gpu.requestAdapter().then(adapter => adapter.requestDevice()).then(device => device.getAdapterInfo().then(info => info.totalMemory)) : null;
    const networkTraffic = navigator.connection ? navigator.connection.downlink : null;

    console.log(`CPU Usage: ${cpuUsage} cores`);
    console.log(`GPU Usage: ${gpuUsage} MB`);
    console.log(`Network Traffic: ${networkTraffic} Mbps`);

    // Send data to server (optional)
    fetch('/api/metrics', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({
            cpuUsage: cpuUsage,
            gpuUsage: gpuUsage,
            networkTraffic: networkTraffic
        })
    });
}, 5000); // Log every 5 seconds
```

### Example Server-Side Endpoint
Here’s an example of a server-side endpoint to receive and store the metrics:

```javascript
const express = require('express');
const bodyParser = require('body-parser');
const app = express();

app.use(bodyParser.json());

app.post('/api/metrics', (req, res) => {
    const { cpuUsage, gpuUsage, networkTraffic } = req.body;

    // Store metrics in database (e.g., InfluxDB)
    // Example using InfluxDB
    const influx = require('influx');
    const client = new influx.InfluxDB({
        host: 'localhost',
        database: 'coinhive_metrics'
    });

    const point = {
        measurement: 'mining_metrics',
        fields: {
            cpuUsage: cpuUsage,
            gpuUsage: gpuUsage,
            networkTraffic: networkTraffic
        }
    };

    client.writePoints([point], (err) => {
        if (err) {
            console.error(err);
            res.status(500).send('Error storing metrics');
        } else {
            res.status(200).send('Metrics stored successfully');
        }
    });
});

app.listen(3000, () => {
    console.log('Server listening on port 3000');
});
```

